def parse_dependencies_from_ldd_output(content):
    if type(content) == str:
        content = content.split('\n')

    dependencies = []
    for line in content:
        if re.search(r'^\s*(/.*?)\s*=>\s*ldd\s*\(', line):
            continue
        match = re.search(r'=>\s*(/.*?)\s*\(', line)
        match = match or re.search(r'\s*(/.*?)\s*\(', line)
        if match:
            dependencies.append(match.group(1))

    return dependencies


